const body = $input.first().json.body ?? $input.first().json;
const info = $('Info').first().json;
const normalizePhone = (value = '') => String(value).replace(/\D/g, '');

// Ignora se não for mensagem válida
if (!body.data || !body.data.message) {
  return [];
}

const message = body.data;
const isFromMe = message.key?.fromMe === true;
const isGroup = message.key?.remoteJid?.includes('@g.us');
const isStatus = message.key?.remoteJid === 'status@broadcast';

if (isFromMe || isGroup || isStatus) {
  return [];
}

// Extrai dados relevantes
const telefone = normalizePhone(message.key?.remoteJid || '');
const messageType = message.messageType || '';
const isAudio = messageType === 'audioMessage';
const texto = message.message?.conversation
  || message.message?.extendedTextMessage?.text
  || '';
const pushName = message.pushName || '';
const whitelistEnabled = info.test_sender_whitelist_enabled === true;
const whitelist = String(info.test_sender_whitelist_numbers || '')
  .split(',')
  .map((item) => normalizePhone(item))
  .filter(Boolean);

if (whitelistEnabled && !whitelist.includes(telefone)) {
  return [];
}

// Permite áudio mesmo sem texto
if (!texto.trim() && !isAudio) {
  return [];
}

return [{
  json: {
    telefone,
    texto,
    pushName,
    messageId: message.key.id,
    messageType,
    timestamp: new Date().toISOString()
  }
}];

