const normalizePhone = (value = '') => String(value).replace(/\D/g, '');
const docs = $input.first().json.documents || [];
const targetPhone = normalizePhone($('Filtrar Mensagens').first().json.telefone || '');

const parseField = (field) => {
  if (!field || typeof field !== 'object') return field;

  const valueKey = Object.keys(field).find((key) => key.endsWith('Value'));
  if (valueKey) return field[valueKey];

  if (field.mapValue) {
    const mapFields = field.mapValue.fields || {};
    const obj = {};
    for (const [key, value] of Object.entries(mapFields)) {
      obj[key] = parseField(value);
    }
    return obj;
  }

  if (field.arrayValue) {
    const values = field.arrayValue.values || [];
    return values.map(parseField);
  }

  return field;
};

for (const doc of docs) {
  const parsedData = {};
  for (const [key, value] of Object.entries(doc.fields || {})) {
    parsedData[key] = parseField(value);
  }

  const docPhone = normalizePhone(parsedData.whatsapp || parsedData.phone || '');
  if (!docPhone || docPhone !== targetPhone) {
    continue;
  }

  return [{
    json: {
      id: doc.name?.split('/').pop() || null,
      ...parsedData
    }
  }];
}

return [{ json: {} }];

const tsRaw = $('Formata JSON').first().json.time_agent_off

if (!tsRaw || tsRaw === '' || tsRaw === null || tsRaw === undefined) {
  return [{ json: { hoursPassed: 999 } }];
}

let tsMillis = null;
let valid = true;

if (typeof tsRaw === 'number') {
  tsMillis = tsRaw < 1e12 ? tsRaw * 1000 : tsRaw;
} else if (typeof tsRaw === 'string') {
  const digitsOnly = /^\d+$/;
  if (digitsOnly.test(tsRaw)) {
    const n = Number(tsRaw);
    tsMillis = n < 1e12 ? n * 1000 : n;
  } else {
    const parsed = Date.parse(tsRaw);
    if (Number.isNaN(parsed)) {
      valid = false;
    } else {
      tsMillis = parsed;
    }
  }
} else {
  valid = false;
}

let hoursPassed = 999;
if (valid && tsMillis) {
  const now = Date.now();
  hoursPassed = (now - tsMillis) / (1000 * 60 * 60);
}

return [{ json: { hoursPassed } }];

const ultimaMensagemDaFila = $input.last();
const mensagemDoWorkflow = $('Enfileirar mensagem.').first();
const latestId = ultimaMensagemDaFila.json.id ?? ultimaMensagemDaFila.json.id_mensagem ?? null;
const currentId = mensagemDoWorkflow.json.id ?? mensagemDoWorkflow.json.id_mensagem ?? null;

if (latestId !== null && currentId !== null && latestId !== currentId) {
  return [];
}

const texto = $input
  .all()
  .map((item) => item.json.message ?? '')
  .filter(Boolean)
  .join('\n');

if (!texto) {
  return [];
}

return [{ json: { texto } }];

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buffer.toString('base64');

return [{
  json: {
    audioBase64: base64
  }
}];

const raw = $('AI Agent Vendas').first().json.output || '';
const fallback = {
  responseToCustomer: String(raw || '').trim(),
  sendProductImages: [],
  finishThread: true,
  continueService: ''
};

const sanitizeImages = (images) => (Array.isArray(images) ? images : [])
  .map((item) => ({
    url: String(item?.url || '').trim(),
    caption: String(item?.caption || '').trim()
  }))
  .filter((item) => item.url)
  .slice(0, 2);

try {
  const cleaned = String(raw).trim().replace(/^```json\s*/i, '').replace(/^```/, '').replace(/```$/, '').trim();
  const parsed = JSON.parse(cleaned);
  return [{
    json: {
      responseToCustomer: String(parsed.responseToCustomer || fallback.responseToCustomer).trim(),
      sendProductImages: sanitizeImages(parsed.sendProductImages),
      finishThread: parsed.finishThread !== false,
      continueService: String(parsed.continueService || '').trim()
    }
  }];
} catch (error) {
  return [{ json: fallback }];
}
